1	export type Customer = {
2	  yearsWithMHPCO: number;
3	};
4	
5	export type Item = {
6	  type: string;
7	  material?: string;
8	  cursed?: boolean;
9	  enchantment?: number;
10	};
11	
12	export type QuoteStep = {
13	  op: "quote";
14	  items: Item[];
15	};
16	
17	export type Damage = {
18	  itemType: string;
19	  amount: number;
20	};
21	
22	export type Incident = {
23	  cause: string;
24	  damages: Damage[];
25	};
26	
27	export type ClaimStep = {
28	  op: "claim";
29	  policy: number;
30	  incident: Incident;
31	};
32	
33	export type Step = QuoteStep | ClaimStep;
34	
35	export type Scenario = {
36	  customer: Customer;
37	  steps: Step[];
38	};
39	
40	export type ClaimResult = {
41	  payout: number;
42	  remainingCap: number;
43	};
44	
45	export type Result = {
46	  premium?: number;
47	  payout?: number;
48	  remainingCap?: number;
49	};
50	
51	const PROCESSING_FEE = 5;
52	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
53	const CURSE_SURCHARGE_RATE = 0.5;
54	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
55	const HIGH_ENCHANTMENT_MINIMUM = 5;
56	const LOYALTY_DISCOUNT_RATE = 0.2;
57	const LOYALTY_MINIMUM_YEARS = 2;
58	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
59	
60	const BASE_PREMIUMS: Record<string, number> = {
61	  sword: 100,
62	  amulet: 60,
63	  staff: 80,
64	  potion: 40,
65	  rune: 25,
66	  moonstone: 25,
67	};
68	
69	const COMPONENT_BLOCK_SIZE = 3;
70	const COMPONENT_BLOCK_PREMIUM = 60;
71	
72	const countByType = (items: Item[]): Map<string, number> => {
73	  const counts = new Map<string, number>();
74	  for (const item of items) {
75	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
76	  }
77	  return counts;
78	};
79	
80	const groupBasePremium = ([type, count]: [string, number]): number =>
81	  count === COMPONENT_BLOCK_SIZE
82	    ? COMPONENT_BLOCK_PREMIUM
83	    : count * BASE_PREMIUMS[type];
84	
85	const sumBy = <T>(values: T[], amount: (value: T) => number): number =>
86	  values.reduce((total, value) => total + amount(value), 0);
87	
88	const assertKnownItemTypes = (items: Item[]): void => {
89	  for (const item of items) {
90	    if (!(item.type in BASE_PREMIUMS)) {
91	      throw new Error(`Unknown item type: ${item.type}`);
92	    }
93	  }
94	};
95	
96	const computeBasePremium = (items: Item[]): number =>
97	  sumBy([...countByType(items)], groupBasePremium);
98	
99	const itemCurseSurcharge = (item: Item): number =>
100	  item.cursed ? BASE_PREMIUMS[item.type] * CURSE_SURCHARGE_RATE : 0;
101	
102	const enchantmentOf = (item: Item): number => item.enchantment ?? 0;
103	
104	const itemHighEnchantmentSurcharge = (item: Item): number =>
105	  enchantmentOf(item) >= HIGH_ENCHANTMENT_MINIMUM
106	    ? BASE_PREMIUMS[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE
107	    : 0;
108	
109	const quotePremium = (
110	  customer: Customer,
111	  items: Item[],
112	  isFollowUp: boolean,
113	): number => {
114	  const basePremium = computeBasePremium(items);
115	  const curseSurcharge = sumBy(items, itemCurseSurcharge);
116	  const highEnchantmentSurcharge = sumBy(items, itemHighEnchantmentSurcharge);
117	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
118	  const loyaltyDiscount =
119	    customer.yearsWithMHPCO >= LOYALTY_MINIMUM_YEARS
120	      ? basePremium * LOYALTY_DISCOUNT_RATE
121	      : 0;
122	  const followUpDiscount = isFollowUp
123	    ? basePremium * FOLLOW_UP_DISCOUNT_RATE
124	    : 0;
125	  const unroundedPremium =
126	    basePremium +
127	    curseSurcharge +
128	    highEnchantmentSurcharge +
129	    firstInsuranceSurcharge -
130	    loyaltyDiscount -
131	    followUpDiscount +
132	    PROCESSING_FEE;
133	  return Math.ceil(unroundedPremium);
134	};
135	
136	const DEDUCTIBLE = 100;
137	const PAYOUT_CAP_MULTIPLIER = 2;
138	const HALF_REIMBURSEMENT_MINIMUM_ENCHANTMENT = 8;
139	const HALF_REIMBURSEMENT_RATE = 0.5;
140	
141	const INSURANCE_VALUES: Record<string, number> = {
142	  sword: 1000,
143	  amulet: 600,
144	  rune: 250,
145	};
146	
147	const insuranceValueOf = (item: Item): number => INSURANCE_VALUES[item.type];
148	
149	const reimbursementFor = (insuredItem: Item, damage: Damage): number =>
150	  enchantmentOf(insuredItem) >= HALF_REIMBURSEMENT_MINIMUM_ENCHANTMENT
151	    ? damage.amount * HALF_REIMBURSEMENT_RATE
152	    : damage.amount;
153	
154	const requireInsuredItem = (insuredItems: Item[], damage: Damage): Item => {
155	  const insuredItem = insuredItems.find((item) => item.type === damage.itemType);
156	  if (insuredItem === undefined) {
157	    throw new Error(`Item not in policy: ${damage.itemType}`);
158	  }
159	  return insuredItem;
160	};
161	
162	const assertDamageCountsCovered = (
163	  insuredItems: Item[],
164	  damages: Damage[],
165	): void => {
166	  const insuredCounts = countByType(insuredItems);
167	  const damageCounts = new Map<string, number>();
168	  for (const damage of damages) {
169	    damageCounts.set(
170	      damage.itemType,
171	      (damageCounts.get(damage.itemType) ?? 0) + 1,
172	    );
173	  }
174	  for (const [type, count] of damageCounts) {
175	    if (count > (insuredCounts.get(type) ?? 0)) {
176	      throw new Error(`More ${type} damages than insured: ${type}`);
177	    }
178	  }
179	};
180	
181	const damagePayout = (insuredItems: Item[], damage: Damage): number =>
182	  reimbursementFor(requireInsuredItem(insuredItems, damage), damage) -
183	  DEDUCTIBLE;
184	
185	const settleClaim = (
186	  insuredItems: Item[],
187	  damages: Damage[],
188	  remainingCap: number,
189	): ClaimResult => {
190	  assertDamageCountsCovered(insuredItems, damages);
191	  const uncappedPayout = sumBy(damages, (damage) =>
192	    damagePayout(insuredItems, damage),
193	  );
194	  const unroundedPayout = Math.min(uncappedPayout, remainingCap);
195	  const payout = Math.floor(unroundedPayout);
196	  return { payout, remainingCap: remainingCap - payout };
197	};
198	
199	const policyOf = (scenario: Scenario, claim: ClaimStep): QuoteStep =>
200	  scenario.steps[claim.policy] as QuoteStep;
201	
202	const initialCapOf = (policy: QuoteStep): number =>
203	  PAYOUT_CAP_MULTIPLIER * sumBy(policy.items, insuranceValueOf);
204	
205	export const processScenario = (scenario: Scenario): { results: Result[] } => {
206	  const remainingCaps = new Map<number, number>();
207	  return {
208	    results: scenario.steps.map((step, index) => {
209	      if (step.op === "quote") {
210	        assertKnownItemTypes(step.items);
211	        const isFollowUp = index > 0;
212	        return { premium: quotePremium(scenario.customer, step.items, isFollowUp) };
213	      }
214	      const policy = policyOf(scenario, step);
215	      const remainingCap =
216	        remainingCaps.get(step.policy) ?? initialCapOf(policy);
217	      const result = settleClaim(
218	        policy.items,
219	        step.incident.damages,
220	        remainingCap,
221	      );
222	      remainingCaps.set(step.policy, result.remainingCap);
223	      return result;
224	    }),
225	  };
226	};
